import json
import pandas as pd
import re

contents_path = var_call_S0MTOyjARnN0m6j7nEdsJFJH
languages_path = var_call_rg6sDxkaAVnRq6EGjWDdowTF

contents = pd.read_json(contents_path)
languages = pd.read_json(languages_path)

# find rows where sample_path contains .swift (case-insensitive)
contents['sample_path_lower'] = contents['sample_path'].str.lower()
swift_mask = contents['sample_path_lower'].str.contains('.swift')
swift_files = contents[swift_mask].copy()

# exclude binary mentions
swift_files = swift_files[~swift_files['repo_data_description'].str.lower().str.contains('binary', na=False)].copy()

# extract copy counts robustly
def extract_copy_count(desc):
    if not isinstance(desc, str):
        return 1
    d = desc.lower()
    # try 'copied X times' or 'copied X'
    m = re.search(r"copied\s+(\d+)\s+times", d)
    if m:
        return int(m.group(1))
    m = re.search(r"copied\s+(\d+)", d)
    if m:
        return int(m.group(1))
    m = re.search(r"(\d+)\s+times", d)
    if m:
        return int(m.group(1))
    m = re.search(r"appearing\s+(\d+)\s+times", d)
    if m:
        return int(m.group(1))
    m = re.search(r"appearing\s+(\d+)", d)
    if m:
        return int(m.group(1))
    m = re.search(r"duplicated\s+(\d+)\s+times", d)
    if m:
        return int(m.group(1))
    # fallback: find numbers and pick the one <=100 maybe copy count
    nums = [int(x) for x in re.findall(r"(\d+)", d)]
    # remove sizes in bytes
    sizes = [n for m in re.finditer(r"(\d+)\s+bytes", d) for n in [int(m.group(1))]]
    candidates = [n for n in nums if n not in sizes]
    smalls = [n for n in candidates if n<=100]
    if smalls:
        return max(smalls)
    if candidates:
        return max(candidates)
    return 1

swift_files['copy_count'] = swift_files['repo_data_description'].apply(extract_copy_count)

# aggregate by id
agg = swift_files.groupby('id', as_index=False).agg({'copy_count': 'max'})
if agg.empty:
    out = {'error': 'no swift files found'}
    print('__RESULT__:')
    print(json.dumps(out))
else:
    max_count = int(agg['copy_count'].max())
    max_ids = agg[agg['copy_count']==max_count]['id'].tolist()
    # get candidate rows for these ids
    candidates = swift_files[swift_files['id'].isin(max_ids)][['id','sample_repo_name','sample_path','repo_data_description','copy_count']].drop_duplicates()
    # languages swift repo set
    swift_repos_set = set(languages['repo_name'].tolist())
    # find intersection
    repos_with_file = sorted(candidates['sample_repo_name'].unique().tolist())
    repos_in_languages = [r for r in repos_with_file if r in swift_repos_set]
    out = {
        'max_copy_count': max_count,
        'max_ids': max_ids,
        'repos_with_file': repos_with_file,
        'repos_in_languages': repos_in_languages,
        'candidate_records': candidates.to_dict(orient='records')
    }
    print('__RESULT__:')
    print(json.dumps(out))

